// src/components/Sidebar.js
import React, { useState } from 'react'; // Đã thêm useState vào import
import { Link } from 'react-router-dom';
import '../Dashboard.css'; // Sử dụng CSS chung cho dashboard layout

function Sidebar({ userRole }) {
  // Lấy vai trò từ localStorage (biến này hiện không được sử dụng trực tiếp trong JSX nhưng có thể hữu ích cho các logic khác)
  const role = localStorage.getItem('role'); 
  // State để quản lý việc mở/đóng menu con "Đăng ký và quản lý"
  const [openRegisterManage, setOpenRegisterManage] = useState(false);
  // State để quản lý việc mở/đóng menu con "Thống kê, báo cáo"
  const [openStatsReport, setOpenStatsReport] = useState(false);

  return (
    <div className="sidebar">
      {/* Header của Sidebar, chứa avatar và vai trò người dùng.
          Class "sidebar-header" được sử dụng để điều khiển ẩn/hiện khi sidebar thu gọn/mở rộng. */}
      <div className="sidebar-header"> {/* Đã đổi tên từ user-info-wrapper thành sidebar-header */}
        {/* Hình ảnh placeholder cho avatar người dùng. Cần thay thế bằng ảnh thực tế. */}
        <img src="https://placehold.co/50x50/000/FFF?text=User" alt="User Avatar" className="user-avatar" />
        {/* Hiển thị vai trò của người dùng (Quản trị viên hoặc Nhân viên) */}
        <span className="user-role">{userRole === 'admin' ? 'Quản trị viên' : 'Nhân viên'}</span>
      </div>

      {/* Phần điều hướng chính của Sidebar */}
      <nav className="sidebar-nav">
        <ul>
          {/* Mục "Đăng ký và quản lý" (có thể mở rộng) */}
          <li className="sidebar-item">
            {/* Header của menu con "Đăng ký và quản lý" */}
            <a
              href="#" // Sử dụng href="#" hoặc ngăn chặn hành vi mặc định nếu không có liên kết chính
              className={`summary ${openRegisterManage ? 'open' : ''}`} // Thêm class 'open' khi menu mở
              onClick={(e) => { // Ngăn chặn hành vi mặc định của thẻ a
                e.preventDefault(); 
                setOpenRegisterManage(!openRegisterManage); // Chuyển đổi trạng thái mở/đóng khi click
              }} 
            >
              <span className="menu-icon">
                {/* Icon cho Đăng ký và quản lý (Lucide clipboard-list SVG) */}
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="lucide lucide-clipboard-list"><rect width="8" height="4" x="8" y="2" rx="1" ry="1"/><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 0-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"/><path d="M12 11h4"/><path d="M12 15h4"/><path d="M8 11h.01"/><path d="M8 15h.01"/></svg>
              </span>
              <span className="menu-text">Đăng ký và quản lý</span>
              {/* Icon mũi tên để chỉ ra menu con */}
              <span className="arrow-icon">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={`lucide lucide-chevron-down ${openRegisterManage ? 'rotate-180' : ''}`}><path d="m6 9 6 6 6-6"/></svg>
              </span>
            </a>
            {/* Hiển thị menu con khi openRegisterManage là true */}
            {openRegisterManage && (
              <ul className="submenu">
                {/* Mục con: Khai báo cơ sở nuôi */}
                <li><Link to="/khai-bao">📄 Khai báo cơ sở nuôi</Link></li>
                {/* Mục con: Quản lý Cơ sở nuôi */}
                <li><Link to="/admin/farms">📝 Quản lý Cơ sở nuôi</Link></li>
              </ul>
            )}
          </li>

          {/* Mục "Thống kê và báo cáo" (có thể mở rộng) */}
          <li className="sidebar-item">
            {/* Header của menu con "Thống kê và báo cáo" */}
            <a
              href="#" // Sử dụng href="#" hoặc ngăn chặn hành vi mặc định nếu không có liên kết chính
              className={`summary ${openStatsReport ? 'open' : ''}`} // Thêm class 'open' khi menu mở
              onClick={(e) => { // Ngăn chặn hành vi mặc định của thẻ a
                e.preventDefault(); 
                setOpenStatsReport(!openStatsReport); // Chuyển đổi trạng thái mở/đóng khi click
              }}
            >
              <span className="menu-icon">
                {/* Icon cho Thống kê, báo cáo (Lucide bar-chart SVG) */}
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className="lucide lucude-bar-chart"><line x1="12" x2="12" y1="20" y2="10"/><line x1="18" x2="18" y1="20" y2="4"/><line x1="6" x2="6" y1="20" y2="16"/></svg>
              </span>
              <span className="menu-text">Thống kê, báo cáo</span>
              {/* Icon mũi tên để chỉ ra menu con */}
              <span className="arrow-icon">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={`lucide lucide-chevron-down ${openStatsReport ? 'rotate-180' : ''}`}><path d="m6 9 6 6 6-6"/></svg>
              </span>
            </a>
            {/* Hiển thị menu con khi openStatsReport là true */}
            {openStatsReport && (
              <ul className="submenu">
                <li><Link to="/stats-report/subA">📈 Mục con Thống kê A</Link></li>
                <li><Link to="/stats-report/subB">📊 Mục con Thống kê B</Link></li>
              </ul>
            )}
          </li>

          {/* Các mục menu chính khác */}
          <li>
            <Link to="/dashboard">
              <span className="menu-icon">📊</span> {/* Biểu tượng Dashboard */}
              <span className="menu-text">Dashboard</span> {/* Văn bản Dashboard */}
            </Link>
          </li>
          {userRole === 'admin' && (
            <>
              <li>
                <Link to="/admin/users">
                  <span className="menu-icon">👥</span> {/* Biểu tượng Quản lý Người dùng */}
                  <span className="menu-text">Quản lý Người dùng</span> {/* Văn bản Quản lý Người dùng */}
                </Link>
              </li>
              <li>
                <Link to="/admin/customers">
                  <span className="menu-icon">🧑‍🤝‍🧑</span> {/* Biểu tượng Quản lý Khách hàng */}
                  <span className="menu-text">Quản lý Khách hàng</span> {/* Văn bản Quản lý Khách hàng */}
                </Link>
              </li>
            </>
          )}
          {/* Mục Đăng xuất */}
          <li>
            <Link to="/logout">
              <span className="menu-icon">🚪</span> {/* Biểu tượng Đăng xuất */}
              <span className="menu-text">Đăng xuất</span> {/* Văn bản Đăng xuất */}
            </Link>
          </li>
        </ul>
      </nav>
    </div>
  );
}

export default Sidebar;
